 {"id":"bd-2w6","title":"Implement StartupBanner struct and rendering","description":"# Implement StartupBanner Struct and Rendering

## Purpose
Create the main StartupBanner component that orchestrates the entire startup display sequence - combining the logo, server info, capabilities table, and status indicators into a cohesive, informative startup experience.

## What the Banner Shows
When a FastMCP server starts, humans should see:
1. **Logo**: ASCII art with gradient (establishes brand)
2. **Server Info Panel**: Name, version, description
3. **Capabilities Table**: Tools, resources, prompts counts with status
4. **Ready Status**: Confirmation that server is ready
5. **Transport Info**: What transport is active (stdio, SSE, etc.)

## Implementation

### File: crates/fastmcp-console/src/banner.rs

```rust
//! Startup banner for FastMCP servers.
//!
//! Displays a beautiful banner when the server starts, showing
//! server info, capabilities, and ready status.

use rich_rust::prelude::*;
use crate::console::FastMcpConsole;
use crate::theme::theme;

/// Builder for the startup banner
pub struct StartupBanner {
    /// Server name (from ServerInfo)
    server_name: String,
    /// Server version
    version: String,
    /// Optional description/instructions
    description: Option<String>,
    /// Number of registered tools
    tools_count: usize,
    /// Number of registered resources
    resources_count: usize,
    /// Number of registered prompts
    prompts_count: usize,
    /// Transport type being used
    transport: String,
    /// Whether to show the logo
    show_logo: bool,
}

impl StartupBanner {
    /// Create a new banner with server name and version
    pub fn new(server_name: impl Into<String>, version: impl Into<String>) -> Self {
        Self {
            server_name: server_name.into(),
            version: version.into(),
            description: None,
            tools_count: 0,
            resources_count: 0,
            prompts_count: 0,
            transport: "stdio".to_string(),
            show_logo: true,
        }
    }

    /// Set the server description
    pub fn description(mut self, desc: impl Into<String>) -> Self {
        self.description = Some(desc.into());
        self
    }

    /// Set the number of tools
    pub fn tools(mut self, count: usize) -> Self {
        self.tools_count = count;
        self
    }

    /// Set the number of resources
    pub fn resources(mut self, count: usize) -> Self {
        self.resources_count = count;
        self
    }

    /// Set the number of prompts
    pub fn prompts(mut self, count: usize) -> Self {
        self.prompts_count = count;
        self
    }

    /// Set the transport type
    pub fn transport(mut self, transport: impl Into<String>) -> Self {
        self.transport = transport.into();
        self
    }

    /// Disable the logo (show only info)
    pub fn no_logo(mut self) -> Self {
        self.show_logo = false;
        self
    }

    /// Render the complete banner
    pub fn render(&self, console: &FastMcpConsole) {
        if !console.is_rich() {
            self.render_plain();
            return;
        }

        let theme = theme();

        // 1. Logo (if enabled)
        if self.show_logo {
            render_logo(console);
            console.newline();
        }

        // 2. Server info panel
        self.render_info_panel(console, theme);
        console.newline();

        // 3. Capabilities table
        self.render_capabilities_table(console, theme);
        console.newline();

        // 4. Ready status
        self.render_ready_status(console, theme);

        // 5. Divider
        console.rule(None);
    }

    fn render_info_panel(&self, console: &FastMcpConsole, theme: &FastMcpTheme) {
        let title_line = format!(
            "[{}]{}[/] [{}]v{}[/]",
            theme.primary.hex(),
            self.server_name,
            theme.text_muted.hex(),
            self.version
        );

        let mut content = title_line;

        if let Some(desc) = &self.description {
            content.push_str(&format!(
                "\n[{}]{}[/]",
                theme.text_dim.hex(),
                desc
            ));
        }

        content.push_str(&format!(
            "\n[{}]High-performance Model Context Protocol framework[/]",
            theme.text_dim.hex()
        ));

        let panel = Panel::from_text(&content)
            .border_style(theme.border_style.clone())
            .rounded();

        console.inner.print_renderable(&panel);
    }

    fn render_capabilities_table(&self, console: &FastMcpConsole, theme: &FastMcpTheme) {
        let mut table = Table::new()
            .title("Capabilities")
            .title_style(theme.header_style.clone())
            .box_style(&rich_rust::r#box::ROUNDED)
            .border_style(theme.border_style.clone())
            .show_header(true);

        table = table
            .add_column(Column::new("Type").style(theme.label_style.clone()))
            .add_column(Column::new("Count").justify(JustifyMethod::Right))
            .add_column(Column::new("Status"));

        // Tools row
        let tools_status = if self.tools_count > 0 {
            format!("[{}]✓ registered[/]", theme.success.hex())
        } else {
            format!("[{}]○ none[/]", theme.text_dim.hex())
        };
        table.add_row_cells(["Tools", &self.tools_count.to_string(), &tools_status]);

        // Resources row
        let resources_status = if self.resources_count > 0 {
            format!("[{}]✓ registered[/]", theme.success.hex())
        } else {
            format!("[{}]○ none[/]", theme.text_dim.hex())
        };
        table.add_row_cells(["Resources", &self.resources_count.to_string(), &resources_status]);

        // Prompts row
        let prompts_status = if self.prompts_count > 0 {
            format!("[{}]✓ registered[/]", theme.success.hex())
        } else {
            format!("[{}]○ none[/]", theme.text_dim.hex())
        };
        table.add_row_cells(["Prompts", &self.prompts_count.to_string(), &prompts_status]);

        console.inner.print_renderable(&table);
    }

    fn render_ready_status(&self, console: &FastMcpConsole, theme: &FastMcpTheme) {
        console.print(&format!(
            "[{}]✓[/] Server ready on [{}]{}[/]",
            theme.success.hex(),
            theme.accent.hex(),
            self.transport
        ));
    }

    /// Plain text fallback for agent/CI contexts
    fn render_plain(&self) {
        eprintln!("FastMCP Server: {} v{}", self.server_name, self.version);
        if let Some(desc) = &self.description {
            eprintln!("  {}", desc);
        }
        eprintln!("  Tools: {}", self.tools_count);
        eprintln!("  Resources: {}", self.resources_count);
        eprintln!("  Prompts: {}", self.prompts_count);
        eprintln!("  Transport: {}", self.transport);
        eprintln!("Server ready.");
    }
}
