### Fallback Behavior

If rich logging init fails, fall back to standard tracing:

```rust
fn init_rich_logging(&self) -> Result<(), Error> {
    match RichSubscriberBuilder::new()
        .with_level_filter(log_level)
        .init() 
    {
        Ok(()) => Ok(()),
        Err(e) => {
            // Fall back to standard fmt subscriber
            eprintln\!("Warning: Rich logging unavailable: {}", e);
            tracing_subscriber::fmt()
                .with_max_level(log_level)
                .with_writer(std::io::stderr)
                .init();
            Ok(())
        }
    }
}
```

